import { Vex } from '@vex_dev/sdk';
import { ChatFlow } from 'flowise';

const vex = new Vex({
  projectId: 'csirt-prod',
  apiKey: process.env.VEX_API_KEY
});

const flow = new ChatFlow();
flow.setCallbackHandler(async (data) => {
  const result = await vex.verify({
    guardrail: 'threat-intel-no-leak',
    input: data.input,
    output: data.output,
    context: { ioc_types: ['ip', 'hash', 'domain'] }
  });
  if (!result.pass) {
    throw new Error(`Vex blocked: ${result.reason}`);
  }
  return data;
});

// Deploy to Flowise canvas

flow.on('vectorRetrieval', async (docs, query) => {
  const embeddings = await vex.embed(docs.map(d => d.pageContent));
  const scores = embeddings.map((e, i) => 
    cosineSimilarity(e, vex.embed(query)[0])
  );

  const validDocs = docs.filter((_, i) => scores[i] > 0.8);

  if (validDocs.length === 0) {
    return vex.verify({
      guardrail: 'rag-relevance-fail',
      metadata: { avg_score: scores.reduce((a,b)=>a+b)/scores.length }
    });
  }
  return validDocs;
});

flow.on('toolCall', async (toolCall) => {
  if (['firewall_block', 'isolate_host', 'escalate_incident'].includes(toolCall.name)) {
    const approval = await vex.verify({
      guardrail: 'human-approval-required',
      input: toolCall.args,
      policy: 'critical-action-hold',
      notify: ['soc-team@company.com']
    });

    if (!approval.pass) {
      await vex.notify({
        channel: 'slack',
        message: `Approval needed: ${JSON.stringify(toolCall.args)}`
      });
      throw new Error('Human approval required');
    }
  }
  return toolCall;
});
